checker_dsl:
EXISTS (`expression E`) {
  AND {
    (`expression E may evaluate to null (nullExpr)`),
    OR {
      EXISTS (`enhanced for statement FOR`) { (`FOR uses E as its iterable expression`) },
      EXISTS (`synchronized statement SYNCH`) { (`SYNCH uses E as its monitor expression`) },
      EXISTS (`switch statement SWITCH`) {
        AND {
          (`SWITCH uses E as its selector expression`),
          NOT { (`SWITCH has a case null label`) }
        }
      },
      EXISTS (`switch expression SWITCH_EXPR`) {
        AND {
          (`SWITCH_EXPR uses E as its selector expression`),
          NOT { (`SWITCH_EXPR has a case null label`) }
        }
      },
      EXISTS (`field access FA`, `field F`) {
        AND {
          (`FA uses E as its qualifier expression`),
          (`FA accesses field F`),
          NOT { (`field F is static`) }
        }
      },
      EXISTS (`method call MC`, `method M`) {
        AND {
          (`MC uses E as its qualifier expression`),
          (`MC invokes method M`),
          NOT { (`method M is static`) }
        }
      },
      EXISTS (`class instance creation expression CIE`) { (`CIE uses E as its qualifier expression`) },
      EXISTS (`array access AA`) { (`AA uses E as its array expression`) },
      EXISTS (`cast expression CAST`) {
        AND {
          OR {
            (`CAST is an explicit cast (CastExpr)`),
            (`CAST is an implicit cast (ImplicitCastExpr)`)
          },
          (`CAST uses E as its operand expression`),
          (`the type of E is a boxed type (e.g., Integer)`),
          (`the target type of CAST is a primitive type (e.g., int)`)
        }
      },
      AND {
        (`the type of E is a boxed type`),
        OR {
          EXISTS (`array access AA2`) { (`AA2 uses E as its index expression`) },
          EXISTS (`array creation expression ACE`) { (`ACE uses E as one of its dimension expressions`) },
          EXISTS (`local variable declaration LVDE`, `local variable LV`) {
            AND {
              (`LVDE declares local variable LV`),
              (`the type of LV is a primitive type`),
              (`LVDE uses E as the initializer for LV`)
            }
          },
          EXISTS (`assignment expression AE`, `assignable destination DEST`) {
            AND {
              (`AE assigns to destination DEST`),
              (`the type of DEST is a primitive type`),
              (`AE uses E as its source expression`)
            }
          },
          EXISTS (`assignment operator expression AOE`) {
            AND {
              (`AOE uses E as its source expression`),
              (`the type of AOE is a primitive type`)
            }
          },
          EXISTS (`equality test expression EQ`, `expression OP`) {
            AND {
              (`EQ is an equality test (e.g., ==, !=)`),
              (`EQ has operand OP`),
              (`OP is E`),
              (`the type of OP is a primitive type`)
            }
          },
          EXISTS (`binary expression BIN`, `expression OP2`) {
            AND {
              (`BIN is a binary expression`),
              NOT { (`BIN is an equality test`) },
              (`BIN has operand OP2`),
              (`OP2 is E`),
              (`the type of BIN is a primitive type`)
            }
          },
          EXISTS (`unary expression UN`) { (`UN uses E as its operand expression`) },
          EXISTS (`conditional expression CHOOSE`) {
            AND {
              (`the type of CHOOSE is a primitive type`),
              EXISTS (`expression RES`) {
                AND {
                  (`CHOOSE has a result expression RES`),
                  (`RES is E`)
                }
              }
            }
          },
          EXISTS (`condition node COND`) { (`COND uses E as its condition expression`) },
          EXISTS (`parameter P`, `argument A`) {
            AND {
              (`the type of parameter P is a primitive type`),
              (`P receives argument A`),
              (`A is E`)
            }
          },
          EXISTS (`return statement RET`, `callable C`) {
            AND {
              (`RET is a return statement`),
              (`RET belongs to callable C`),
              (`the return type of C is a primitive type`),
              (`RET uses E as its return expression`)
            }
          }
        }
      }
    }
  }
}
